import uuid

class InvalidCartError(Exception): pass
class PermissionDeniedError(Exception): pass
class InvalidDiscountCodeError(Exception): pass
class PaymentFailedError(Exception): pass

class CheckoutProcess:
    def __init__(self, user_id, user_role, user_tier):
        self.user_id = user_id
        self.user_role = user_role # e.g., 'user', 'admin'
        self.user_tier = user_tier # e.g., 'standard', 'premium', 'vip'

    def _validate_cart_items(self, cart_items):
        if not cart_items:
            raise InvalidCartError("Cart cannot be empty.")
        
        # Simulate inventory check, item validity, etc.
        for item in cart_items:
            if not isinstance(item, dict) or 'id' not in item or 'price' not in item or 'quantity' not in item:
                raise InvalidCartError("Each cart item must be a dictionary with 'id', 'price', and 'quantity'.")
            if item['price'] <= 0 or item['quantity'] <= 0:
                raise InvalidCartError(f"Invalid price or quantity for item {item.get('id', 'N/A')}.")
        
        # Calculate subtotal before discounts
        subtotal = sum(item['price'] * item['quantity'] for item in cart_items)
        return {"validated_cart": cart_items, "subtotal": subtotal, "applied_discount_value": 0}

    def _apply_discount_codes(self, checkout_data, discount_codes=None):
        validated_cart = checkout_data['validated_cart']
        subtotal = checkout_data['subtotal']
        
        if not discount_codes:
            return checkout_data # No discounts to apply

        # Simulate discount database/rules
        available_discounts = {
            "SAVE10": {"type": "percentage", "value": 0.10, "min_subtotal": 50, "permissions": {"roles": [], "tiers": []}},
            "ADMIN20": {"type": "percentage", "value": 0.20, "min_subtotal": 100, "permissions": {"roles": ["admin"], "tiers": []}},
            "VIP50": {"type": "fixed", "value": 50, "min_subtotal": 200, "permissions": {"roles": [], "tiers": ["vip"]}},
            "FREESHIP": {"type": "shipping", "value": 0, "min_subtotal": 20, "permissions": {"roles": [], "tiers": []}},
        }
        
        applied_discount_value = 0
        applied_discount_details = []
        
        for code in discount_codes:
            discount_info = available_discounts.get(code)
            if not discount_info:
                raise InvalidDiscountCodeError(f"Discount code '{code}' is invalid.")

            # Check permissions
            required_roles = discount_info['permissions']['roles']
            required_tiers = discount_info['permissions']['tiers']

            if required_roles and self.user_role not in required_roles:
                raise PermissionDeniedError(f"User '{self.user_id}' does not have permission to use discount code '{code}'.")
            if required_tiers and self.user_tier not in required_tiers:
                raise PermissionDeniedError(f"User '{self.user_id}' does not have the required tier to use discount code '{code}'.")

            if subtotal < discount_info['min_subtotal']:
                raise InvalidDiscountCodeError(f"Discount code '{code}' requires a minimum subtotal of {discount_info['min_subtotal']}.")
            
            if discount_info['type'] == "percentage":
                discount_amount = subtotal * discount_info['value']
                applied_discount_value += discount_amount
                applied_discount_details.append(f"{code}: -{discount_info['value']*100:.0f}% (${discount_amount:.2f})")
            elif discount_info['type'] == "fixed":
                discount_amount = discount_info['value']
                applied_discount_value += discount_amount
                applied_discount_details.append(f"{code}: -${discount_amount:.2f}")
            elif discount_info['type'] == "shipping":
                # Handle shipping discounts separately if shipping costs are involved
                # For this example, we'll just acknowledge it or reduce a hypothetical shipping cost
                applied_discount_details.append(f"{code}: Free Shipping")
                # Assume shipping cost reduction is handled elsewhere or becomes 0.
                # Not directly affecting applied_discount_value here unless shipping is part of the 'total'
        
        final_subtotal_after_discounts = max(0, subtotal - applied_discount_value)
        return {
            "validated_cart": validated_cart,
            "subtotal": subtotal,
            "applied_discount_value": applied_discount_value,
            "final_subtotal_after_discounts": final_subtotal_after_discounts,
            "applied_discount_details": applied_discount_details
        }

    def _calculate_tax(self, checkout_data, tax_rate=0.08):
        final_subtotal_after_discounts = checkout_data['final_subtotal_after_discounts']
        
        tax_amount = final_subtotal_after_discounts * tax_rate
        total_amount = final_subtotal_after_discounts + tax_amount
        
        return {
            **checkout_data,
            "tax_rate": tax_rate,
            "tax_amount": tax_amount,
            "total_amount": total_amount
        }

    def _process_payment(self, checkout_data, payment_details):
        total_amount = checkout_data['total_amount']
        
        # Simulate payment gateway interaction
        # In a real system, this would involve calling an external API
        if not payment_details or payment_details.get('card_number') == 'INVALID':
            raise PaymentFailedError("Payment processing failed. Invalid card details.")
        
        # Assume payment is successful
        transaction_id = str(uuid.uuid4())
        
        return {
            **checkout_data,
            "payment_status": "success",
            "transaction_id": transaction_id,
            "payment_method": payment_details.get('method', 'credit_card')
        }

    def _create_order_record(self, checkout_data):
        # Simulate database insertion
        order_id = str(uuid.uuid4())
        order_record = {
            "order_id": order_id,
            "user_id": self.user_id,
            "items": checkout_data['validated_cart'],
            "subtotal_before_discount": checkout_data['subtotal'],
            "applied_discount_value": checkout_data['applied_discount_value'],
            "final_subtotal_after_discounts": checkout_data['final_subtotal_after_discounts'],
            "tax_amount": checkout_data['tax_amount'],
            "tax_rate": checkout_data['tax_rate'],
            "total_amount": checkout_data['total_amount'],
            "payment_status": checkout_data['payment_status'],
            "transaction_id": checkout_data['transaction_id'],
            "payment_method": checkout_data['payment_method'],
            "order_status": "completed",
            "applied_discount_details": checkout_data.get("applied_discount_details", [])
        }
        
        # In a real application, you would save this to a database
        # print(f"Order {order_id} created successfully for user {self.user_id}.")
        
        return {"order_record": order_record}

    def execute_checkout(self, cart_items, discount_codes=None, payment_details=None):
        try:
            # Step 1: Validate cart items
            checkout_data = self._validate_cart_items(cart_items)

            # Step 2: Apply discount codes
            checkout_data = self._apply_discount_codes(checkout_data, discount_codes)
            
            # Step 3: Calculate tax
            checkout_data = self._calculate_tax(checkout_data)

            # Step 4: Process payment
            checkout_data = self._process_payment(checkout_data, payment_details)

            # Step 5: Create order record
            final_output = self._create_order_record(checkout_data)

            return final_output

        except (InvalidCartError, PermissionDeniedError, InvalidDiscountCodeError, PaymentFailedError) as e:
            # Handle specific checkout errors
            raise e
        except Exception as e:
            # Handle unexpected errors
            raise Exception(f"An unexpected error occurred during checkout: {e}")

